/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. &IsAuthorized = SecGAMIsAuthByFunctionalityKey.Udp(!'<Check_Is_Authenticated>') If &IsAuthorized
LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Comissão Vendas"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PesSts.IsEmpty() &FilterPesStsValueDescription = &PesSts.EnumerationDescription()
print printBlockFilterPesSts EndIf If not &PesCod.IsEmpty() print printBlockFilterPesCod EndIf If not &PesRaz.IsEmpty() print printBlockFilterPesRaz EndIf If not &IncluirDemitidos.IsEmpty() &FilterIncluirDemitidosValueDescription = '' Do Case Case &IncluirDemitidos.ToString().Trim() = !"S" &FilterIncluirDemitidosValueDescription = "Incluir Demitidos"
Case &IncluirDemitidos.ToString().Trim() = !"N" &FilterIncluirDemitidosValueDescription = " Vendedores Vigêntes"
EndCase
print printBlockFilterIncluirDemitidos EndIf If not &PesComUltLct.IsEmpty() print printBlockFilterPesComUltLct EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PesRaz when &OrderedBy = 1 order PesCod when &OrderedBy = 2 AND &OrderedDsc = False order (PesCod) when &OrderedBy = 2 AND &OrderedDsc = True order PesRaz when &OrderedBy = 3 AND &OrderedDsc = False order (PesRaz) when &OrderedBy = 3 AND &OrderedDsc = True order PesSts when &OrderedBy = 4 AND &OrderedDsc = False order (PesSts) when &OrderedBy = 4 AND &OrderedDsc = True order PesIsVen when &OrderedBy = 5 AND &OrderedDsc = False order (PesIsVen) when &OrderedBy = 5 AND &OrderedDsc = True order PesIsFun when &OrderedBy = 6 AND &OrderedDsc = False order (PesIsFun) when &OrderedBy = 6 AND &OrderedDsc = True order PesCidUfeCod when &OrderedBy = 7 AND &OrderedDsc = False order (PesCidUfeCod) when &OrderedBy = 7 AND &OrderedDsc = True order PesCidNom when &OrderedBy = 8 AND &OrderedDsc = False order (PesCidNom) when &OrderedBy = 8 AND &OrderedDsc = True order PesVenAreCod when &OrderedBy = 9 AND &OrderedDsc = False order (PesVenAreCod) when &OrderedBy = 9 AND &OrderedDsc = True order PesVenAreNom when &OrderedBy = 10 AND &OrderedDsc = False order (PesVenAreNom) when &OrderedBy = 10 AND &OrderedDsc = True
using DSWWVendedorComissao(&PesSts, &PesCod, &PesRaz, &IncluirDemitidos, &PesComUltLct) &PesStsDescription = PesSts.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWVendedorComissaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWVendedorComissaoGridState")) Else &GridState.FromXml(&Session.Get(!"WWVendedorComissaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PESSTS" &PesSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESRAZ" &PesRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"INCLUIRDEMITIDOS" &IncluirDemitidos.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOMULTLCT" &PesComUltLct.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

Output_file("ExportReportWWVendedorComissao","PDF");

